const CATS = [{"id": 1, "name": "الكل"}, {"id": 2, "name": "عينات"}, {"id": 3, "name": "عطور كاملة"}, {"id": 4, "name": "نيش"}, {"id": 5, "name": "كريد"}, {"id": 6, "name": "أمواج"}];
const PER_PAGE = 20;

module.exports = async (req, res) => {
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET, POST, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');
  if (req.method === 'OPTIONS') return res.status(200).end();
  const { type, page = '1' } = req.query;
  const pageNum = parseInt(page);
  if (type === 'categories') return res.status(200).json({ success: true, data: CATS });
  if (type === 'products') {
    const start = (pageNum - 1) * PER_PAGE;
    const data = ALL_PRODUCTS.slice(start, start + PER_PAGE);
    const hasMore = start + PER_PAGE < ALL_PRODUCTS.length;
    return res.status(200).json({ success: true, data, page: pageNum, hasMore });
  }
  res.status(400).json({ success: false, error: 'Invalid type' });
};